const enabled = $env.N8N_WORKFLOW_SLO_MONITOR_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: true, reason: 'kill_switch_disabled' } }];
}
const requestId = 'ops-slo-monitor-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = 'n8n-slo-monitor-' + new Date().toISOString().slice(0, 16);
const crypto = require('crypto');
const payloadHash = crypto.createHash('sha256').update(JSON.stringify({ action: 'ops.slo_monitor', ts: new Date().toISOString().slice(0, 16) })).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(requestId + 'ops.slo_monitor' + payloadHash).digest('hex');
return [{ json: { killed: false, requestId, correlationId, idempotencyKey, timestamp: new Date().toISOString() } }];

const calls = $input.all().map(i => i.json);
const flat = Array.isArray(calls[0]) ? calls[0] : calls;
if (flat.length === 0) return [{ json: { breach: false, message: 'No data', p95: 0, errorRate: 0, totalCalls: 0 } }];

const durations = flat.map(c => c.duration_ms || 0).sort((a, b) => a - b);
const p95Index = Math.ceil(durations.length * 0.95) - 1;
const p95 = durations[p95Index] || 0;

const failed = flat.filter(c => c.status === 'failed' || c.status === 'timeout').length;
const errorRate = (failed / flat.length) * 100;

const SLO_P95_MS = 5000;
const SLO_ERROR_RATE = 5;

const breach = p95 > SLO_P95_MS || errorRate > SLO_ERROR_RATE;

return [{ json: { breach, p95, errorRate: Math.round(errorRate * 100) / 100, totalCalls: flat.length, sloP95: SLO_P95_MS, sloErrorRate: SLO_ERROR_RATE } }];
